+  cnnInitialized = true;
+  if (!JSON_OUTPUT) {
+    console.log(`[cnn] Initialized: embeddingDim=${savedDim}, inputSize=${CNN_INPUT_SIZE}x${CNN_INPUT_SIZE}`);
