+// ---------------------------------------------------------------------------
+// Cognitum Seed Ingest
+// ---------------------------------------------------------------------------
+
+/**
+ * Send a 128-dim embedding to Cognitum Seed's RVF vector store.
+ * @param {Float32Array} embedding
