+      const t0 = Date.now();
+      const embedding = extractEmbedding(win);
+      const embedMs = Date.now() - t0;
+
+      const meta = {
+        timestamp: frame.timestamp,
+        nodeId,
+        windowIdx: windowCount,
+        rssi: frame.rssi || 0,
+        nSubcarriers,
