+  for (let sc = 0; sc < nSubcarriers; sc++) {
+    const offset = sc * 4;
+    if (offset + 4 > iqHex.length) break;
+    const iVal = parseInt(iqHex.substring(offset, offset + 2), 16);
+    const qVal = parseInt(iqHex.substring(offset + 2, offset + 4), 16);
