+    for (let f = 0; f < nFrames; f++) {
+      const amp = this.frames[f].amplitudes;
+      for (let i = 0; i < nSc; i++) {
+        mean[i] += amp[i];
+      }
+    }
+    for (let i = 0; i < nSc; i++) mean[i] /= nFrames;
+
+    for (let f = 0; f < nFrames; f++) {
+      const amp = this.frames[f].amplitudes;
+      for (let i = 0; i < nSc; i++) {
+        const d = amp[i] - mean[i];
+        std[i] += d * d;
+      }
+    }
+    for (let i = 0; i < nSc; i++) {
+      std[i] = Math.sqrt(std[i] / (nFrames - 1));
+    }
