+    for (const [nodeId, window] of this.windows) {
+      const corr = window.correlationMatrix();
+      if (!corr || !corr.matrix || corr.n < 2) {
+        perNode[nodeId] = { personCount: 0, activeSubcarriers: corr ? corr.n : 0, groups: [], edges: 0 };
+        continue;
+      }
