+  const charIdx = Math.min(Math.floor(clamped * (BAR_CHARS.length - 1)), BAR_CHARS.length - 1);
+  return BAR_CHARS[charIdx].repeat(filled).padEnd(maxWidth);
+}
+
+function renderVisualization(outputSmoothed, stats, frameCount, opts) {
